mapper.select:
SELECT sol.id, sol.dept_id, sol.title, sol.request_method, sol.type, sol.ip, sol.status, sol.create_time, su.username as creator_username, su.nickname as creator_nickname FROM sys_operate_log sol INNER JOIN sys_user su ON sol.create_by = su.id WHERE sol.enabled = '1'
AND (su.username LIKE CONCAT(#{req.creator},'%') OR su.nickname LIKE CONCAT(#{req.creator},'%'))
AND sol.title LIKE CONCAT(#{req.title},'%')
AND sol.request_url LIKE CONCAT(#{req.requestUrl},'%')
AND sol.request_method = #{req.requestMethod}
AND sol.type = #{req.type}
AND sol.status = #{req.status}
AND sol.create_time BETWEEN #{req.startTime} AND #{req.endTime}
${req.dataScopeSql}
ORDER BY sol.id DESC

SELECT sol.id, sol.dept_id, sol.title, sol.request_method, sol.type, sol.ip, sol.status, sol.create_time, su.username as creator_username, su.nickname as creator_nickname FROM sys_operate_log sol INNER JOIN sys_user su ON sol.create_by = su.id WHERE sol.enabled = '1'
AND (su.username LIKE CONCAT(#{req.creator},'%') OR su.nickname LIKE CONCAT(#{req.creator},'%'))
AND sol.title LIKE CONCAT(#{req.title},'%')
AND sol.request_url LIKE CONCAT(#{req.requestUrl},'%')
AND sol.request_method = #{req.requestMethod}
AND sol.type = #{req.type}
AND sol.status = #{req.status}
AND sol.create_time BETWEEN TO_DATE(#{req.startTime}, 'yyyy-mm-dd hh24:mi:ss') AND TO_DATE(#{req.endTime}, 'yyyy-mm-dd hh24:mi:ss')
${req.dataScopeSql}
ORDER BY sol.id DESC
